+    final NetworkResponse response = await NetworkCaller().getRequest(
+      ApiLinks.allEmpresas,
+    );
+
+    if (response.isSuccess && response.body != null) {
+      final List<dynamic> data = response.body!['data']['dados'] ?? [];
+      setState(() {
+        _empresas.clear();
+        _empresas.addAll(
+          data
