+                  setState(() {
+                    _empresaId = value;
+                  });
+                },
+                isExpanded: true,
+              ),
+              const SizedBox(height: 16),
+              OutlinedButton(
+                onPressed: _selectFile,
+                child: const Text('Selecionar Arquivo'),
+              ),
+              const SizedBox(height: 8),
+              Text(
+                _selectedFile != null
